using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Mapa-Múndi (GDD "Estrutura Geral do Mapa-Múndi"): representa um RAMO/RAIZ
/// entre dois <see cref="WorldMapNode"/> — o caminho físico que a "bola de luz"
/// percorre, os planos de câmara ("trechos") configuráveis ao longo desse
/// percurso, e os pontos-chave de transição visual (luz, neblina, partículas)
/// usados por <c>WorldMapController</c>.
///
/// IMPORTANTE — direcção da árvore: <see cref="fromNode"/> é sempre o nó mais
/// próximo do Coração de Gaia ("nó-pai"); <see cref="toNode"/> é o nó mais
/// afastado ("nó-filho"). Esta convenção define a regra de "revelação de
/// áreas e raízes" do GDD:
/// <list type="bullet">
/// <item><description>Este ramo fica ILUMINADO/atravessável quando <c>fromNode</c> estiver desbloqueado (<see cref="IsLit"/>).</description></item>
/// <item><description><c>toNode</c> fica ALCANÇÁVEL (a bola pode viajar até lá, painel mostra o custo) assim que este ramo estiver iluminado — mesmo que <c>toNode</c> continue bloqueado.</description></item>
/// <item><description>Os ramos que partem de <c>toNode</c> só ficam iluminados quando <c>toNode</c> for desbloqueado — por isso "dá para chegar até lá, mas não atravessar sem pagar".</description></item>
/// </list>
/// </summary>
[DisallowMultipleComponent]
public class WorldMapConnection : MonoBehaviour
{
    [Header("Nós Ligados")]
    [Tooltip("Nó de ORIGEM (mais próximo do Coração de Gaia). Este ramo só fica iluminado/atravessável quando este nó estiver desbloqueado.")]
    public WorldMapNode fromNode;

    [Tooltip("Nó de DESTINO (mais afastado do Coração de Gaia). Fica 'alcançável' assim que 'fromNode' for desbloqueado, mesmo que continue bloqueado.")]
    public WorldMapNode toNode;

    [Header("Caminho")]
    [Tooltip("Pontos intermédios do caminho, em ordem de 'fromNode' para 'toNode' (NÃO incluir os próprios nós — as posições deles são usadas automaticamente como extremidades). Pode ficar vazio para uma ligação em linha recta.")]
    public Transform[] waypoints;

    [Header("Câmara — Trechos (\"Shots\")")]
    [Tooltip("Lista de planos de câmara ao longo deste ramo. 'progress' vai de 0 (em fromNode) a 1 (em toNode). À medida que a bola avança, a câmara faz blend para o plano mais avançado cujo 'progress' já foi atingido — permite controlo preciso de quando uma área entra em quadro, drama do boss, aproximação/afastamento de Gaia, etc. Não precisa de estar ordenada (é ordenada automaticamente por 'progress' em runtime).")]
    public List<CameraShot> cameraShots = new List<CameraShot>();

    [Header("Transição Visual entre Regiões")]
    [Tooltip("Pontos-chave de luminosidade/cor/neblina/clima/partículas ao longo do ramo, interpolados pelo progresso da bola (WorldMapController.ApplyVisualKeyframes). Não precisa de estar ordenada.")]
    public List<RegionVisualKeyframe> visualKeyframes = new List<RegionVisualKeyframe>();

    [Header("Mundo")]
    [Tooltip("Mundo a que este ramo pertence — usado para WorldData.rootColor/rootColorPostBoss (cor da raiz, normal vs. pós-boss). Deixar vazio para ramos neutros próximos do Coração de Gaia (comuns a vários mundos).")]
    public WorldData world;

    [Header("Visual da Raiz (opcional)")]
    [Tooltip("LineRenderer usado para desenhar este ramo no Mapa-Múndi. Se atribuído, a sua cor é actualizada automaticamente (apagado/sombrio se !IsLit, WorldData.rootColor ou rootColorPostBoss se IsLit).")]
    public LineRenderer rootRenderer;

    [Tooltip("Cor usada para o ramo enquanto NÃO estiver iluminado (sombrio/escuro).")]
    public Color unlitColor = new Color(0.25f, 0.25f, 0.3f, 1f);

    // -------------------- Estado --------------------

    /// <summary>Este ramo está iluminado/atravessável — verdadeiro quando 'fromNode' estiver desbloqueado (ou for o Coração de Gaia).</summary>
    public bool IsLit => fromNode != null && fromNode.IsUnlocked;

    // -------------------- Caminho --------------------

    /// <summary>Lista completa de pontos do caminho, incluindo as posições de fromNode e toNode.</summary>
    public List<Vector3> GetFullPath()
    {
        var points = new List<Vector3>();

        if (fromNode != null) points.Add(fromNode.transform.position);

        if (waypoints != null)
            foreach (var wp in waypoints)
                if (wp != null) points.Add(wp.position);

        if (toNode != null) points.Add(toNode.transform.position);

        return points;
    }

    /// <summary>Comprimento total do caminho (soma das distâncias entre pontos consecutivos).</summary>
    public float GetLength()
    {
        var pts = GetFullPath();
        float len = 0f;
        for (int i = 1; i < pts.Count; i++)
            len += Vector3.Distance(pts[i - 1], pts[i]);
        return len;
    }

    /// <summary>Posição no mundo correspondente ao progresso 0-1 ao longo do caminho (0 = fromNode, 1 = toNode).</summary>
    public Vector3 GetPositionAtProgress(float t)
    {
        t = Mathf.Clamp01(t);
        var pts = GetFullPath();

        if (pts.Count == 0) return transform.position;
        if (pts.Count == 1) return pts[0];

        float total = GetLength();
        if (total <= 0f) return pts[0];

        float target = t * total;
        float covered = 0f;

        for (int i = 1; i < pts.Count; i++)
        {
            float segLen = Vector3.Distance(pts[i - 1], pts[i]);

            if (covered + segLen >= target || i == pts.Count - 1)
            {
                float segT = segLen > 0f ? Mathf.Clamp01((target - covered) / segLen) : 0f;
                return Vector3.Lerp(pts[i - 1], pts[i], segT);
            }

            covered += segLen;
        }

        return pts[pts.Count - 1];
    }

    // -------------------- Visual da Raiz --------------------

    /// <summary>Actualiza a cor/visibilidade de 'rootRenderer' de acordo com IsLit e o estado de boss do mundo (chamado por WorldMapController.RefreshAllNodeVisuals).</summary>
    public void RefreshRootVisual()
    {
        if (rootRenderer == null) return;

        Color color;

        if (!IsLit)
        {
            color = unlitColor;
        }
        else if (world != null)
        {
            bool postBoss = PlayerProgress.Instance != null && PlayerProgress.Instance.HasDefeatedBoss(world);
            color = postBoss ? world.rootColorPostBoss : world.rootColor;
        }
        else
        {
            color = Color.white;
        }

        rootRenderer.startColor = color;
        rootRenderer.endColor = color;

        var pts = GetFullPath();
        rootRenderer.positionCount = pts.Count;
        for (int i = 0; i < pts.Count; i++)
            rootRenderer.SetPosition(i, pts[i]);
    }

    private void OnDrawGizmos()
    {
        var pts = GetFullPath();
        Gizmos.color = IsLit ? Color.yellow : new Color(0.4f, 0.4f, 0.45f);

        for (int i = 1; i < pts.Count; i++)
            Gizmos.DrawLine(pts[i - 1], pts[i]);
    }
}

/// <summary>
/// Um "plano"/trecho de câmara configurável no Inspector ao longo de um
/// <see cref="WorldMapConnection"/>. Ver <see cref="WorldMapCameraRig.FollowConnectionProgress"/>.
/// </summary>
[System.Serializable]
public class CameraShot
{
    [Range(0f, 1f)]
    [Tooltip("Progresso ao longo do ramo (0 = fromNode, 1 = toNode) a partir do qual este plano passa a ser o alvo da câmara.")]
    public float progress;

    [Tooltip("Ponto da cena que define a posição (X/Y) da câmara neste trecho (ex: um GameObject vazio colocado à frente da área que deve entrar em quadro). Se vazio, usa a posição do próprio ramo em 'progress'.")]
    public Transform cameraAnchor;

    [Tooltip("Tamanho ortográfico (zoom) da câmara neste trecho. Valores maiores = câmara mais afastada.")]
    public float orthographicSize = 5f;

    [Tooltip("Duração (segundos) do movimento/zoom da câmara até este plano.")]
    public float blendDuration = 1f;

    [Tooltip("Nome opcional, apenas para organização no Inspector (ex: \"Aproximação à Clareira\", \"Drama da Coroa\", \"Afastar para Gaia\").")]
    public string label;
}

/// <summary>
/// Ponto-chave de transição visual entre regiões (GDD "Transição visual entre
/// regiões"), associado a um progresso 0-1 ao longo de um
/// <see cref="WorldMapConnection"/>. <c>WorldMapController.ApplyVisualKeyframes</c>
/// interpola entre dois pontos-chave consecutivos de acordo com o progresso da
/// bola e aplica o resultado à luz ambiente/neblina globais (RenderSettings) e
/// a sistemas de partículas de chuva/neve/ambiente configurados no Inspector.
/// </summary>
[System.Serializable]
public class RegionVisualKeyframe
{
    [Range(0f, 1f)]
    [Tooltip("Progresso ao longo do ramo (0 = fromNode, 1 = toNode) onde este conjunto de valores se aplica totalmente.")]
    public float progress;

    [Header("Luz / Cor Ambiente")]
    public Color ambientColor = Color.white;
    [Range(0f, 3f)] public float ambientIntensity = 1f;

    [Header("Neblina")]
    [Range(0f, 1f)] public float fogDensity;
    public Color fogColor = Color.gray;

    [Header("Clima / Partículas (0-1)")]
    [Tooltip("Intensidade da chuva (0 = sem chuva, 1 = intensidade máxima configurada em WorldMapController.maxRainEmissionRate).")]
    [Range(0f, 1f)] public float rainIntensity;

    [Tooltip("Intensidade da neve (0 = sem neve, 1 = intensidade máxima configurada em WorldMapController.maxSnowEmissionRate).")]
    [Range(0f, 1f)] public float snowIntensity;

    [Tooltip("Intensidade de partículas ambiente/decorativas (pólen, vagalumes, fuligem, etc.).")]
    [Range(0f, 1f)] public float ambientParticlesIntensity;

    [Tooltip("Nome opcional, apenas para organização no Inspector (ex: \"Saída de Gaia\", \"Atmosfera do Bosque\", \"Pós-Boss\").")]
    public string label;
}
